// /frontend/src/components/Radar.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import { MapContainer, TileLayer, ZoomControl } from "react-leaflet";
import "leaflet/dist/leaflet.css";

/**
 * One clean radar: precipitation + snow
 * - No scroll wheel zoom (won't hijack page scroll)
 * - Pulls the latest radar frame time from RainViewer
 * - Graceful fallback if the API hiccups
 */
export default function Radar({
  center = [33.7490, -84.3880],   // Atlanta default; pass your own [lat, lng]
  zoom = 6,
  height = 320,
  className = ""
}) {
  const [frameTime, setFrameTime] = useState(null);
  const alive = useRef(true);

  // Get latest available radar time from RainViewer
  useEffect(() => {
    alive.current = true;
    (async () => {
      try {
        const res = await fetch("https://api.rainviewer.com/public/weather-maps.json");
        const data = await res.json();
        // Prefer the most recent *past* frame (always rendered)
        const latest = data?.radar?.past?.at(-1)?.time ?? data?.radar?.nowcast?.at(0)?.time;
        if (alive.current && latest) setFrameTime(latest);
      } catch {
        // Swallow; we'll use a static fallback below
      }
    })();
    return () => { alive.current = false; };
  }, []);

  // If API fails, use a reasonable ~current timestamp fallback (works but may be stale)
  const effectiveTime = useMemo(() => {
    if (frameTime) return frameTime;
    // fallback ~now rounded to 10 minutes (RainViewer tiles are ~10-min cadence)
    const now = Math.floor(Date.now() / (10 * 60 * 1000)) * (10 * 60);
    return now;
  }, [frameTime]);

  // RainViewer single-layer tiles (composited reflectivity with snow)
  // Format: /v2/radar/{time}/256/{z}/{x}/{y}/2/1_1.png
  // trailing "1_1" means smooth=1 & snow=1 (snow overlay ON)
  const radarUrl = useMemo(() => {
    return `https://tilecache.rainviewer.com/v2/radar/${effectiveTime}/256/{z}/{x}/{y}/2/1_1.png`;
  }, [effectiveTime]);

  // Base map tiles (light gray, low visual weight)
  const baseUrl = "https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png";

  return (
    <div className={`w-full ${className}`} style={{ height }}>
      <MapContainer
        center={center}
        zoom={zoom}
        // IMPORTANT: disable scroll wheel so page scroll keeps working
        scrollWheelZoom={false}
        doubleClickZoom={false}
        zoomControl={false}
        attributionControl={false}
        style={{ width: "100%", height: "100%", borderRadius: "16px", overflow: "hidden" }}
      >
        <TileLayer url={baseUrl} />
        <TileLayer
          url={radarUrl}
          // Keep tiles lightweight and smooth when moving
          updateWhenIdle={true}
          updateWhenZooming={false}
          keepBuffer={4}
          opacity={0.8}
        />
        <ZoomControl position="bottomright" />
      </MapContainer>

      {/* Small hint for users that map is interactive but won't hijack scroll */}
      <div
        className="pointer-events-none"
        style={{
          position: "absolute",
          right: 12,
          bottom: 12,
          padding: "4px 8px",
          borderRadius: 8,
          fontSize: 12,
          backdropFilter: "blur(6px)",
          background: "rgba(0,0,0,0.35)",
          color: "white"
        }}
      >
        Drag to move • use buttons to zoom
      </div>
    </div>
  );
}
